const body = $input.first().json.body || {};
return [{
  json: {
    p_batch_id: body.batch_id || null
  }
}];

const body = $('Webhook - Detect Changes').first().json.body || {};
const produtos = body.produtos || [];
const prevSnapshots = $input.all().map(item => item.json);

// Mapeia snapshots anteriores por anuncio_indice
const prevMap = new Map();
for (const s of prevSnapshots) {
  prevMap.set(String(s.anuncio_indice), s);
}

const alteracoes = [];

for (const prod of produtos) {
  const anuncios = prod.anuncios_detalhados || [];
  for (const cur of anuncios) {
    const idx = String(cur.indice || cur.id_anuncio);
    const prev = prevMap.get(idx);

    if (!prev) {
      // Novo anúncio
      alteracoes.push({
        anuncio: cur.titulo || idx,
        anuncio_indice: idx,
        loja: cur.loja,
        produto: prod.produto,
        campo: 'Status',
        valor_anterior: null,
        valor_atual: cur.status || 'Ativo',
        delta_pct: null,
        tipo: 'novo',
        resumo: `Novo anúncio detectado: ${cur.titulo || idx}`
      });
      continue;
    }

    // Comparar Preço (GMV / Vendas)
    const curVendas = Number(cur.vendas) || 0;
    const curReceita = Number(cur.receita) || 0;
    const prevVendas = Number(prev.vendas) || 0;
    const prevReceita = Number(prev.receita) || 0;

    const curPrice = curVendas > 0 ? (curReceita / curVendas) : 0;
    const prevPrice = prevVendas > 0 ? (prevReceita / prevVendas) : 0;

    if (curPrice > 0 && prevPrice > 0) {
      const deltaPricePct = ((curPrice - prevPrice) / prevPrice) * 100;
      // Threshold de 2%
      if (Math.abs(deltaPricePct) >= 2) {
        alteracoes.push({
          anuncio: cur.titulo || idx,
          anuncio_indice: idx,
          loja: cur.loja,
          produto: prod.produto,
          campo: 'Preço',
          valor_anterior: Math.round(prevPrice * 100) / 100,
          valor_atual: Math.round(curPrice * 100) / 100,
          delta_pct: Math.round(deltaPricePct * 100) / 100,
          tipo: 'preco',
          resumo: `Preço alterado de R$ ${prevPrice.toFixed(2)} para R$ ${curPrice.toFixed(2)} (${deltaPricePct > 0 ? '+' : ''}${Math.round(deltaPricePct)}%)`
        });
      }
    }

    // Comparar Investimento Ads (custo_ads)
    const curAds = Number(cur.custo_ads || cur.investimento_ads) || 0;
    const prevAds = Number(prev.investimento_ads) || 0;
    if (prevAds > 0 || curAds > 0) {
      const prevVal = prevAds || 0;
      const curVal = curAds || 0;
      if (prevVal > 0) {
        const deltaAdsPct = ((curVal - prevVal) / prevVal) * 100;
        // Threshold de 10%
        if (Math.abs(deltaAdsPct) >= 10) {
          alteracoes.push({
            anuncio: cur.titulo || idx,
            anuncio_indice: idx,
            loja: cur.loja,
            produto: prod.produto,
            campo: 'Investimento Ads',
            valor_anterior: prevVal,
            valor_atual: curVal,
            delta_pct: Math.round(deltaAdsPct * 100) / 100,
            tipo: 'investimento',
            resumo: `Investimento Ads alterado de R$ ${prevVal.toFixed(2)} para R$ ${curVal.toFixed(2)} (${deltaAdsPct > 0 ? '+' : ''}${Math.round(deltaAdsPct)}%)`
          });
        }
      }
    }

    // Comparar Status
    if (cur.status && prev.status && cur.status !== prev.status) {
      alteracoes.push({
        anuncio: cur.titulo || idx,
        anuncio_indice: idx,
        loja: cur.loja,
        produto: prod.produto,
        campo: 'Status',
        valor_anterior: prev.status,
        valor_atual: cur.status,
        delta_pct: null,
        tipo: 'status',
        resumo: `Status alterado de ${prev.status} para ${cur.status}`
      });
    }
  }
}

// Procurar anúncios removidos
const curIndices = new Set();
for (const prod of produtos) {
  const anuncios = prod.anuncios_detalhados || [];
  for (const cur of anuncios) {
    curIndices.add(String(cur.indice || cur.id_anuncio));
  }
}
for (const s of prevSnapshots) {
  if (!curIndices.has(String(s.anuncio_indice))) {
    alteracoes.push({
      anuncio: s.titulo || s.anuncio_indice,
      anuncio_indice: s.anuncio_indice,
      loja: s.loja,
      produto: s.produto,
      campo: 'Status',
      valor_anterior: s.status,
      valor_atual: 'Removido',
      delta_pct: null,
      tipo: 'removido',
      resumo: `Anúncio removido: ${s.titulo || s.anuncio_indice}`
    });
  }
}

return [{
  json: {
    alteracoes,
    resumo: `${alteracoes.length} alteração(ões) detectada(s)`
  }
}];
